SELECT players.player_name, players.position, COUNT(DISTINCT tournaments.tournament_id) AS number_of_tournaments
FROM players
JOIN seasons ON players.player_id IN (
    SELECT player_id FROM players WHERE player_id IN (
        SELECT player_id FROM matches WHERE season_id = seasons.season_id
    )
)
JOIN tournaments ON seasons.season_year = tournaments.season_year
WHERE tournaments.qualification_status = 'qualified'
GROUP BY players.player_name, players.position;

SELECT league, COUNT(DISTINCT substr(season_year, 1, 4)) AS distinct_years
FROM seasons
GROUP BY league;

SELECT 
    (SELECT AVG(goals_for) / AVG(total_matches) FROM seasons WHERE season_year = '2019') AS Average_Goals_Per_Match,
    (SELECT AVG(points) FROM seasons WHERE season_year = '2019') AS Average_Points_Per_Game;

SELECT p.player_name, p.position
FROM players p
WHERE p.goals_scored > 1;

SELECT COUNT(DISTINCT season_id) 
FROM matches 
WHERE opponent = 'Team A' AND result = 'win';

SELECT season_year, total_matches
FROM seasons
WHERE ABS(goals_for - goals_against) = (
    SELECT MIN(ABS(goals_for - goals_against))
    FROM seasons
);

SELECT player_id, possession_percentage, shots_on_target, passing_accuracy 
FROM player_metrics 
WHERE passing_accuracy > 80;

SELECT AVG(goals_scored) AS average_goals
FROM players
WHERE position = 'forward';

SELECT DISTINCT s.league
FROM seasons s
JOIN tournaments t ON s.season_year = t.season_year
WHERE t.tournament_name = 'Bulgarian Cup' AND s.season_year = (
    SELECT MIN(season_year) FROM seasons
);
